UPDATE t_p28211681_photo_secure_web.legal_documents
SET title = 'Согласие на получение рекламных и информационных сообщений',
    content = '<h1>Согласие на получение рекламных и информационных сообщений</h1><p>Настоящим я, действуя свободно, своей волей и в своём интересе, даю согласие Пономареву Евгению Викторовичу, ИНН 634502706508, e-mail: support@foto-mix.ru, далее — «Оператор», на получение рекламных, информационных и маркетинговых сообщений о сервисе Foto-Mix, его возможностях, тарифах, акциях, специальных предложениях, обновлениях, мероприятиях и партнёрских программах.</p><p>Сообщения могут направляться следующими способами:</p><p>1.1. по электронной почте;</p><p>1.2. по номеру телефона;</p><p>1.3. в SMS-сообщениях;</p><p>1.4. в мессенджерах;</p><p>1.5. через push-уведомления;</p><p>1.6. через Личный кабинет и интерфейс Сервиса.</p><p>Для целей направления указанных сообщений Оператор вправе обрабатывать следующие мои данные:</p><p>2.1. фамилию, имя, отчество;</p><p>2.2. адрес электронной почты;</p><p>2.3. номер телефона;</p><p>2.4. идентификаторы аккаунта;</p><p>2.5. сведения о подключённом Тарифе, подписке и истории использования Сервиса;</p><p>2.6. данные о согласии или отказе от получения рекламных сообщений.</p><p>Настоящее согласие действует до момента его отзыва.</p><p>Я вправе в любой момент отказаться от получения рекламных и маркетинговых сообщений:</p><p>4.1. по ссылке для отписки, если она содержится в сообщении;</p><p>4.2. через настройки Личного кабинета, если такая функция доступна;</p><p>4.3. путём направления уведомления на адрес support@foto-mix.ru с темой письма «Отказ от рекламных сообщений».</p><p>Оператор прекращает направление рекламных и маркетинговых сообщений в разумный срок после получения отказа, если иное не требуется для завершения уже начатой технической обработки запроса.</p><p>Сервисные, технические и обязательные уведомления, связанные с регистрацией, безопасностью, оплатой, исполнением договора, изменением условий обслуживания и функционированием Личного кабинета, не являются рекламной рассылкой и могут направляться независимо от отзыва настоящего согласия в объёме, необходимом для исполнения договора и требований законодательства РФ.</p>',
    version = version + 1,
    published_at = CURRENT_TIMESTAMP,
    updated_at = CURRENT_TIMESTAMP
WHERE slug = 'privacy-policy';

INSERT INTO t_p28211681_photo_secure_web.legal_document_versions
    (document_id, slug, version, title, content, published_at)
SELECT id, slug, version, title, content, CURRENT_TIMESTAMP
FROM t_p28211681_photo_secure_web.legal_documents
WHERE slug = 'privacy-policy';